args.sparql:
SELECT (YEAR(?born) AS ?birth_year) WHERE {
  wd:Q735776 wdt:P710 ?rider.
  ?rider wdt:P569 ?born.
  ?tour wdt:P31 wd:Q7832;
        wdt:P580 ?start;
        wdt:P710 ?rider.
  FILTER (YEAR(?start) >= 1985 && YEAR(?start) <= 1989)
} GROUP BY ?rider ?born HAVING (COUNT(DISTINCT ?tour) = 4)
